const b = $json.body || {};
const userId = b.user_id || 'user';
const email = b.email || '';
const weekStart = b.week_start || '';
const weekEnd = b.week_end || '';
const runDate = b.run_date || '';

const stats = b.weekly_stats || {};
const pulse = b.portfolio_pulse || {};
const topWeeklySignals = (b.top_weekly_signals || []).slice(0, 5);
const topConviction = (b.top_conviction || []).slice(0, 3);
const watchlistAttention = (b.watchlist_attention || []).slice(0, 5);
const discovery = (b.discovery || []).slice(0, 6);
const nextActions = (b.next_actions || []).slice(0, 3);

const row = (txt) => `<tr><td style='padding:8px 10px;border-top:1px solid #173047;color:#d9e7f5;'>${txt}</td></tr>`;

const weeklyRows = topWeeklySignals.length
  ? topWeeklySignals.map((s) => row(`<strong>${s.ticker || ''}</strong> • ${s.signal_type || ''} • ${(s.severity || '').toUpperCase()}<br/><span style='color:#9fc3e6;'>${s.narrative || ''}</span>`)).join('')
  : row('No notable weekly signals.');

const convictionRows = topConviction.length
  ? topConviction.map((s) => row(`<strong>${s.ticker || ''}</strong> • Confidence ${Math.round(Number(s.confidence || 0) * 100)}%<br/><span style='color:#9fc3e6;'>${s.narrative || ''}</span>`)).join('')
  : row('No conviction ideas this week.');

const attentionRows = watchlistAttention.length
  ? watchlistAttention.map((s) => row(`<strong>${s.ticker || ''}</strong> • ${(s.urgency || '').toUpperCase()} • ${s.action_frame || 'Monitor'}`)).join('')
  : row('No watchlist attention signals this week.');

const discoveryRows = discovery.length
  ? discovery.map((s) => row(`<strong>${s.ticker || ''}</strong> • Fit ${Math.round(Number(s.profile_fit_score || 0) * 100)}% • Confidence ${Math.round(Number(s.confidence || 0) * 100)}%`)).join('')
  : row('No discovery matches this week.');

const actionRows = nextActions.length
  ? nextActions.map((x) => row(`• ${x}`)).join('')
  : row('No immediate action required.');

const html = `<!DOCTYPE html>
<html lang='en'>
<head><meta charset='UTF-8'/><meta name='viewport' content='width=device-width,initial-scale=1.0'/></head>
<body style='margin:0;padding:0;background:#050b16;font-family:Arial,Helvetica,sans-serif;color:#e6edf7;'>
<table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#050b16;padding:24px 0;'>
<tr><td align='center'>
<table role='presentation' width='680' cellspacing='0' cellpadding='0' style='max-width:680px;width:100%;background:#0b1220;border-radius:14px;overflow:hidden;border:1px solid #173047;'>

<tr><td style='padding:22px 26px;background:linear-gradient(135deg,#0b1220 0%,#0f1b30 100%);border-bottom:1px solid #173047;'>
  <h1 style='margin:0;font-size:20px;line-height:1.25;color:#ffffff;'>InvestoraAI Weekly Update</h1>
  <p style='margin:6px 0 0;font-size:12px;color:#8fa6bf;'>${weekStart} to ${weekEnd} • User: ${userId}</p>
</td></tr>

<tr><td style='padding:16px 24px 8px;'>
  <h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Week At A Glance</h2>
  <table role='presentation' width='100%' cellspacing='0' cellpadding='0'>
    <tr>
      <td style='padding:10px;border:1px solid #1f3a57;border-radius:8px;background:#081426;font-size:13px;color:#d9e7f5;'><strong style='color:#9fc3e6;'>Total Signals</strong><br/>${stats.total_signals || 0}</td>
      <td width='8'></td>
      <td style='padding:10px;border:1px solid #1f3a57;border-radius:8px;background:#081426;font-size:13px;color:#d9e7f5;'><strong style='color:#9fc3e6;'>High Priority</strong><br/>${stats.high_priority_signals || 0}</td>
      <td width='8'></td>
      <td style='padding:10px;border:1px solid #1f3a57;border-radius:8px;background:#081426;font-size:13px;color:#d9e7f5;'><strong style='color:#9fc3e6;'>Market Regime</strong><br/>${pulse.market_regime || 'Neutral'}</td>
    </tr>
  </table>
</td></tr>

<tr><td style='padding:16px 24px 8px;'><h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Top Weekly Signals</h2><table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#081426;border:1px solid #1f3a57;border-radius:8px;overflow:hidden;'>${weeklyRows}</table></td></tr>
<tr><td style='padding:16px 24px 8px;'><h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Top Conviction Ideas</h2><table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#081426;border:1px solid #1f3a57;border-radius:8px;overflow:hidden;'>${convictionRows}</table></td></tr>
<tr><td style='padding:16px 24px 8px;'><h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Watchlist - Needs Attention</h2><table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#081426;border:1px solid #1f3a57;border-radius:8px;overflow:hidden;'>${attentionRows}</table></td></tr>
<tr><td style='padding:16px 24px 8px;'><h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Discovery Signals</h2><table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#081426;border:1px solid #1f3a57;border-radius:8px;overflow:hidden;'>${discoveryRows}</table></td></tr>
<tr><td style='padding:16px 24px 12px;'><h2 style='margin:0 0 10px;font-size:15px;color:#b7e8ff;'>Next Actions</h2><table role='presentation' width='100%' cellspacing='0' cellpadding='0' style='background:#081426;border:1px solid #1f3a57;border-radius:8px;overflow:hidden;'>${actionRows}</table></td></tr>

<tr><td style='background:#081224;padding:14px 24px;border-top:1px solid #173047;'>
  <p style='margin:0;font-size:11px;color:#7f9dbc;line-height:1.45;'>This update is informational only and not financial advice. Run date: ${runDate}.</p>
</td></tr>

</table>
</td></tr>
</table>
</body>
</html>`;

return [{ json: { to: email, subject: `InvestoraAI Weekly Update (${weekStart} - ${weekEnd})`, html } }];
